"use client";

import {
  useCallback,
  useEffect,
  useId,
  useImperativeHandle,
  useMemo,
  useRef,
} from "react";
import type {
  PropertiesFormHandle,
  PropertiesFormProps,
  SubmitResult,
} from "./types";
import { useFormReducer } from "./hooks/use-form-reducer";
import { useIdFactory } from "./hooks/use-id-factory";
import { useSubmitSpinner } from "./hooks/use-submit-spinner";
import { resolveFieldPermission } from "./lib/resolve-permission";
import {
  safeRunFormValidate,
  validateAllFields,
} from "./lib/validate";
import { ErrorSummary } from "./parts/error-summary";
import { FieldRow, type FocusTarget } from "./parts/field-row";
import { SubmitActions } from "./parts/submit-actions";
import { cn } from "@/lib/utils";

const SCHEMA_INSTABILITY_THRESHOLD = 5;

export function PropertiesForm<T extends Record<string, unknown> = Record<string, unknown>>(
  props: PropertiesFormProps<T>,
) {
  const {
    schema,
    values,
    mode = "read",
    onModeChange,
    onChange,
    onSubmit,
    onCancel,
    resolvePermission,
    validate,
    showSubmitActions = true,
    submitLabel = "Save",
    cancelLabel = "Cancel",
    ariaLabel,
    className,
    ref,
  } = props;

  const reactFormId = useId();
  const formElementId = `${reactFormId}-form`;

  const [state, dispatch] = useFormReducer(values);
  const getIds = useIdFactory();

  const valuesRef = useRef(values);
  const schemaRef = useRef(schema);
  const onChangeRef = useRef(onChange);
  const onSubmitRef = useRef(onSubmit);
  const validateRef = useRef(validate);
  const onCancelRef = useRef(onCancel);
  const onModeChangeRef = useRef(onModeChange);

  useEffect(() => {
    valuesRef.current = values;
    schemaRef.current = schema;
    onChangeRef.current = onChange;
    onSubmitRef.current = onSubmit;
    validateRef.current = validate;
    onCancelRef.current = onCancel;
    onModeChangeRef.current = onModeChange;
  });

  const submitIdRef = useRef(0);
  const focusTargetsRef = useRef<Map<string, FocusTarget>>(new Map());

  const registerFocusTarget = useCallback(
    (key: string, target: FocusTarget | null) => {
      if (target) focusTargetsRef.current.set(key, target);
      else focusTargetsRef.current.delete(key);
    },
    [],
  );

  const focusField = useCallback((key: string) => {
    const target = focusTargetsRef.current.get(key);
    const dev = process.env.NODE_ENV !== "production";
    if (!target) {
      if (!schemaRef.current.some((f) => f.key === key)) {
        if (dev) {
          console.error(
            `[properties-form] focusField("${key}") — unknown field key.`,
          );
        }
        return;
      }
      const field = schemaRef.current.find((f) => f.key === key);
      if (field) {
        const perm = resolveFieldPermission(
          field,
          valuesRef.current,
          resolvePermission as never,
        );
        if (perm === "hidden" && dev) {
          console.warn(
            `[properties-form] focusField("${key}") — field is hidden; no-op.`,
          );
        }
      }
      return;
    }
    target.focus();
  }, [resolvePermission]);

  const handleFieldChange = useCallback(
    (
      _key: string,
      nextValues: Record<string, unknown>,
      error: string | undefined,
    ) => {
      dispatch({
        type: "field-changed",
        key: _key,
        nextValues,
        error,
      });
      onChangeRef.current?.(nextValues as T);
    },
    [dispatch],
  );

  const handleFieldBlur = useCallback(
    (key: string, error: string | undefined) => {
      dispatch({ type: "field-blurred", key, error });
    },
    [dispatch],
  );

  const handleSpinnerShow = useCallback(() => {
    dispatch({ type: "submit-spinner-show" });
  }, [dispatch]);

  useSubmitSpinner(state.pending, handleSpinnerShow);

  const focusFirstErrorKey = useCallback(
    (errors: Record<string, string>) => {
      const firstKey = schemaRef.current.find((f) => errors[f.key])?.key;
      if (firstKey) focusField(firstKey);
    },
    [focusField],
  );

  const submit = useCallback(async (): Promise<SubmitResult> => {
    const submitId = ++submitIdRef.current;
    const currentValues = valuesRef.current;
    const fieldErrors = validateAllFields(schemaRef.current, currentValues);
    const formResult = safeRunFormValidate(validateRef.current, currentValues);
    const merged: Record<string, string> = { ...formResult.errors };
    for (const [k, v] of Object.entries(fieldErrors)) {
      merged[k] = v;
    }

    dispatch({ type: "submit-started" });

    if (Object.keys(merged).length > 0 || formResult.formError) {
      dispatch({
        type: "submit-failed",
        errors: merged,
        formError: formResult.formError,
      });
      focusFirstErrorKey(merged);
      return { ok: false, errors: merged };
    }

    const handler = onSubmitRef.current;
    if (!handler) {
      dispatch({
        type: "submit-succeeded",
        cleanSnapshot: currentValues,
      });
      return { ok: true };
    }

    try {
      const result = await handler(currentValues as T);
      if (submitId !== submitIdRef.current) {
        return result;
      }
      if (result.ok) {
        dispatch({
          type: "submit-succeeded",
          cleanSnapshot: valuesRef.current,
        });
      } else {
        const errors = result.errors ?? {};
        dispatch({
          type: "submit-failed",
          errors,
          formError: undefined,
        });
        focusFirstErrorKey(errors);
      }
      return result;
    } catch (err) {
      if (submitId !== submitIdRef.current) {
        return { ok: false };
      }
      const message =
        err instanceof Error ? err.message : "Unknown error";
      if (process.env.NODE_ENV !== "production") {
        console.error("[properties-form] onSubmit rejected:", err);
      }
      dispatch({
        type: "submit-failed",
        errors: {},
        formError: `Submit failed: ${message}`,
      });
      return { ok: false };
    }
  }, [dispatch, focusFirstErrorKey]);

  const handleSubmitEvent = useCallback(
    (e: React.FormEvent<HTMLFormElement>) => {
      e.preventDefault();
      void submit();
    },
    [submit],
  );

  const handleCancel = useCallback(() => {
    submitIdRef.current++;
    dispatch({ type: "reset", cleanSnapshot: state.cleanSnapshot });
    onChangeRef.current?.(state.cleanSnapshot as T);
    onCancelRef.current?.();
    onModeChangeRef.current?.("read");
  }, [dispatch, state.cleanSnapshot]);

  const reset = useCallback(() => {
    submitIdRef.current++;
    dispatch({ type: "reset", cleanSnapshot: state.cleanSnapshot });
    onChangeRef.current?.(state.cleanSnapshot as T);
  }, [dispatch, state.cleanSnapshot]);

  const markClean = useCallback(() => {
    dispatch({
      type: "mark-clean",
      cleanSnapshot: valuesRef.current,
    });
  }, [dispatch]);

  const isDirty = useCallback(
    () => state.version !== state.cleanVersion,
    [state.version, state.cleanVersion],
  );

  useImperativeHandle(
    ref,
    (): PropertiesFormHandle => ({
      isDirty,
      markClean,
      reset,
      focusField,
      submit,
    }),
    [isDirty, markClean, reset, focusField, submit],
  );

  const editWithoutOnChangeRef = useRef(false);
  useEffect(() => {
    if (mode === "edit" && !onChange) {
      if (!editWithoutOnChangeRef.current) {
        editWithoutOnChangeRef.current = true;
        if (process.env.NODE_ENV !== "production") {
          console.error(
            "[properties-form] mode=\"edit\" requires `onChange` — value commits will be no-ops.",
          );
        }
      }
    } else {
      editWithoutOnChangeRef.current = false;
    }
  }, [mode, onChange]);

  const schemaInstabilityRef = useRef({ last: schema, count: 0, warned: false });
  useEffect(() => {
    const tracker = schemaInstabilityRef.current;
    if (tracker.last === schema) {
      tracker.count = 0;
      return;
    }
    tracker.last = schema;
    tracker.count++;
    if (
      tracker.count > SCHEMA_INSTABILITY_THRESHOLD &&
      !tracker.warned &&
      process.env.NODE_ENV !== "production"
    ) {
      tracker.warned = true;
      console.warn(
        "[properties-form] `schema` prop is changing every render. " +
          "Wrap with `useMemo` or hoist to module scope to avoid memo invalidation.",
      );
    }
  }, [schema]);

  const visibleSchema = useMemo(
    () =>
      schema.filter((f) => {
        const perm = resolveFieldPermission(
          f,
          values,
          resolvePermission as never,
        );
        return perm !== "hidden";
      }),
    [schema, values, resolvePermission],
  );

  const errorVisibleFor = useCallback(
    (key: string): boolean =>
      state.submitAttempted || !!state.blurredWithError[key],
    [state.submitAttempted, state.blurredWithError],
  );

  return (
    <form
      id={formElementId}
      noValidate
      aria-label={ariaLabel}
      aria-busy={state.pending || undefined}
      onSubmit={handleSubmitEvent}
      className={cn("flex flex-col gap-4", className)}
    >
      {state.submitAttempted ? (
        <ErrorSummary
          schema={visibleSchema}
          errors={state.errors}
          formError={state.formError}
          onFocusField={focusField}
        />
      ) : null}
      <div className="flex flex-col gap-4">
        {visibleSchema.map((field) => (
          <FieldRow
            key={field.key}
            field={field}
            values={values}
            mode={mode}
            error={state.errors[field.key]}
            errorVisible={errorVisibleFor(field.key)}
            pending={state.pending}
            hostResolver={resolvePermission as never}
            ids={getIds(field.key)}
            onFieldChange={handleFieldChange}
            onFieldBlur={handleFieldBlur}
            registerFocusTarget={registerFocusTarget}
          />
        ))}
      </div>
      {showSubmitActions && mode === "edit" ? (
        <SubmitActions
          submitLabel={submitLabel}
          cancelLabel={cancelLabel}
          pending={state.pending}
          showSpinner={state.showSpinner}
          onCancel={handleCancel}
          canCancel={!state.pending}
        />
      ) : null}
    </form>
  );
}

export { PropertiesForm } from "./properties-form";
export { flatten, unflatten } from "./lib/flatten";
export type {
  FieldOption,
  FieldPermission,
  FieldRendererProps,
  FieldType,
  FormMode,
  PropertiesFormField,
  PropertiesFormHandle,
  PropertiesFormProps,
  SubmitResult,
} from "./types";
export { meta } from "./meta";

import type { ComponentType, Ref } from "react";

export type FieldType =
  | "string"
  | "number"
  | "boolean"
  | "date"
  | "select"
  | "textarea";

export type FieldPermission = "editable" | "read-only" | "hidden";

export type FormMode = "read" | "edit";

export interface FieldOption {
  value: string;
  label: string;
}

export interface PropertiesFormField {
  key: string;
  type: FieldType;
  label: string;
  description?: string;
  required?: boolean;
  options?: ReadonlyArray<FieldOption>;
  placeholder?: string;
  permission?: FieldPermission;
  permissionReason?: string;
  validate?: (
    value: unknown,
    allValues: Record<string, unknown>,
  ) => string | undefined;
  renderer?: ComponentType<FieldRendererProps>;
}

export interface FieldRendererProps<V = unknown> {
  value: V;
  onChange: (value: V) => void;
  field: PropertiesFormField;
  allValues: Record<string, unknown>;
  mode: FormMode;
  error: string | undefined;
  disabled: boolean;
  fieldId: string;
  errorId: string;
}

export interface SubmitResult {
  ok: boolean;
  errors?: Record<string, string>;
}

export interface PropertiesFormProps<
  T extends Record<string, unknown> = Record<string, unknown>,
> {
  schema: ReadonlyArray<PropertiesFormField>;
  values: T;

  mode?: FormMode;
  onModeChange?: (mode: FormMode) => void;

  onChange?: (values: T) => void;
  onSubmit?: (values: T) => Promise<SubmitResult>;
  onCancel?: () => void;

  resolvePermission?: (
    field: PropertiesFormField,
    values: T,
  ) => FieldPermission | undefined;
  validate?: (values: T) => Record<string, string> | undefined;

  showSubmitActions?: boolean;
  submitLabel?: string;
  cancelLabel?: string;

  ariaLabel?: string;
  className?: string;

  ref?: Ref<PropertiesFormHandle>;
}

export interface PropertiesFormHandle {
  isDirty(): boolean;
  markClean(): void;
  reset(): void;
  focusField(key: string): void;
  submit(): Promise<SubmitResult>;
}

export interface FormState {
  errors: Record<string, string>;
  formError: string | undefined;
  pending: boolean;
  showSpinner: boolean;
  version: number;
  cleanVersion: number;
  cleanSnapshot: Record<string, unknown>;
  submitAttempted: boolean;
  blurredWithError: Record<string, true>;
}

export type FormAction =
  | {
      type: "field-changed";
      key: string;
      nextValues: Record<string, unknown>;
      error: string | undefined;
    }
  | {
      type: "field-blurred";
      key: string;
      error: string | undefined;
    }
  | { type: "submit-started" }
  | { type: "submit-spinner-show" }
  | {
      type: "submit-succeeded";
      cleanSnapshot: Record<string, unknown>;
    }
  | {
      type: "submit-failed";
      errors: Record<string, string>;
      formError: string | undefined;
    }
  | { type: "mark-clean"; cleanSnapshot: Record<string, unknown> }
  | { type: "reset"; cleanSnapshot: Record<string, unknown> };

"use client";

import { AlertCircle } from "lucide-react";
import type { PropertiesFormField } from "../types";
import { cn } from "@/lib/utils";

interface ErrorSummaryProps {
  schema: ReadonlyArray<PropertiesFormField>;
  errors: Record<string, string>;
  formError: string | undefined;
  onFocusField: (key: string) => void;
  className?: string;
}

export function ErrorSummary({
  schema,
  errors,
  formError,
  onFocusField,
  className,
}: ErrorSummaryProps) {
  const orderedKeys = schema
    .map((f) => f.key)
    .filter((k) => errors[k]);
  if (!formError && orderedKeys.length === 0) return null;

  return (
    <div
      role="alert"
      className={cn(
        "mb-4 rounded-md border border-destructive/40 bg-destructive/10 p-3 text-sm text-destructive",
        className,
      )}
    >
      <div className="flex items-start gap-2">
        <AlertCircle aria-hidden="true" className="mt-0.5 size-4 shrink-0" />
        <div className="flex-1">
          <p className="font-medium">
            {formError ?? "Please fix the errors below."}
          </p>
          {orderedKeys.length > 0 ? (
            <ul className="mt-2 space-y-0.5">
              {orderedKeys.map((key) => {
                const field = schema.find((f) => f.key === key);
                const label = field?.label ?? key;
                return (
                  <li key={key}>
                    <button
                      type="button"
                      onClick={() => onFocusField(key)}
                      className="text-left underline underline-offset-2 hover:no-underline focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-destructive/60 focus-visible:rounded-sm"
                    >
                      {label}: {errors[key]}
                    </button>
                  </li>
                );
              })}
            </ul>
          ) : null}
        </div>
      </div>
    </div>
  );
}

"use client";

import { Check, X } from "lucide-react";
import { Switch } from "@/components/ui/switch";
import type { FieldRendererProps } from "../types";

interface BuiltInFieldProps extends FieldRendererProps {
  onBlur: () => void;
  required: boolean;
}

export function FieldBoolean({
  value,
  onChange,
  mode,
  disabled,
  error,
  fieldId,
  errorId,
  onBlur,
  required,
}: BuiltInFieldProps) {
  const checked = value === true;
  if (mode === "read") {
    return (
      <span className="inline-flex items-center gap-1.5 text-sm">
        {checked ? (
          <Check
            aria-label="Yes"
            className="size-4 text-primary"
          />
        ) : (
          <X
            aria-label="No"
            className="size-4 text-muted-foreground"
          />
        )}
        <span className="sr-only">{checked ? "Yes" : "No"}</span>
      </span>
    );
  }
  return (
    <Switch
      id={fieldId}
      checked={checked}
      disabled={disabled}
      onCheckedChange={(next) => onChange(next)}
      onBlur={onBlur}
      aria-required={required || undefined}
      aria-invalid={error ? true : undefined}
      aria-describedby={error ? errorId : undefined}
    />
  );
}

"use client";

import type { FieldRendererProps } from "../types";
import { formatFieldValue } from "../lib/format-value";
import { cn } from "@/lib/utils";

interface BuiltInFieldProps extends FieldRendererProps {
  onBlur: () => void;
  required: boolean;
}

export function FieldDate({
  value,
  onChange,
  field,
  mode,
  disabled,
  error,
  fieldId,
  errorId,
  onBlur,
  required,
}: BuiltInFieldProps) {
  if (mode === "read") {
    return (
      <span className="block font-mono text-sm">
        {formatFieldValue(field, value)}
      </span>
    );
  }
  const inputValue =
    typeof value === "string"
      ? value
      : value instanceof Date && !Number.isNaN(value.getTime())
        ? value.toISOString().slice(0, 10)
        : "";
  return (
    <input
      id={fieldId}
      type="date"
      value={inputValue}
      placeholder={field.placeholder}
      disabled={disabled}
      onChange={(e) => onChange(e.target.value)}
      onBlur={onBlur}
      aria-required={required || undefined}
      aria-invalid={error ? true : undefined}
      aria-describedby={error ? errorId : undefined}
      className={cn(
        "h-8 w-full min-w-0 rounded-lg border border-input bg-transparent px-2.5 py-1 font-mono text-sm transition-colors outline-none",
        "focus-visible:border-ring focus-visible:ring-3 focus-visible:ring-ring/50",
        "disabled:pointer-events-none disabled:cursor-not-allowed disabled:bg-input/50 disabled:opacity-50",
        "aria-invalid:border-destructive aria-invalid:ring-3 aria-invalid:ring-destructive/20",
        "dark:bg-input/30 dark:disabled:bg-input/80",
      )}
    />
  );
}

import { AlertCircle } from "lucide-react";
import { cn } from "@/lib/utils";

interface FieldErrorProps {
  id: string;
  message: string;
  className?: string;
}

export function FieldError({ id, message, className }: FieldErrorProps) {
  return (
    <p
      id={id}
      role="alert"
      className={cn(
        "mt-1 flex items-start gap-1.5 text-xs text-destructive",
        className,
      )}
    >
      <AlertCircle aria-hidden="true" className="mt-0.5 size-3 shrink-0" />
      <span>{message}</span>
    </p>
  );
}

"use client";

import { Input } from "@/components/ui/input";
import type { FieldRendererProps } from "../types";
import { formatFieldValue } from "../lib/format-value";

interface BuiltInFieldProps extends FieldRendererProps {
  onBlur: () => void;
  required: boolean;
}

export function FieldNumber({
  value,
  onChange,
  field,
  mode,
  disabled,
  error,
  fieldId,
  errorId,
  onBlur,
  required,
}: BuiltInFieldProps) {
  if (mode === "read") {
    return (
      <span className="block truncate text-right font-mono text-sm tabular-nums">
        {formatFieldValue(field, value)}
      </span>
    );
  }
  const inputValue =
    value === undefined || value === null
      ? ""
      : typeof value === "number"
        ? Number.isFinite(value)
          ? String(value)
          : ""
        : String(value);
  return (
    <Input
      id={fieldId}
      type="number"
      inputMode="decimal"
      value={inputValue}
      placeholder={field.placeholder}
      disabled={disabled}
      onChange={(e) => {
        const raw = e.target.value;
        if (raw === "") {
          onChange(undefined);
          return;
        }
        const parsed = Number(raw);
        onChange(Number.isNaN(parsed) ? raw : parsed);
      }}
      onBlur={onBlur}
      aria-required={required || undefined}
      aria-invalid={error ? true : undefined}
      aria-describedby={error ? errorId : undefined}
      className="text-right font-mono tabular-nums"
    />
  );
}

"use client";

import {
  Component,
  useCallback,
  useMemo,
  type ComponentType,
  type ErrorInfo,
  type ReactNode,
} from "react";
import type {
  FieldPermission,
  FieldRendererProps,
  FormMode,
  PropertiesFormField,
} from "../types";
import { resolveFieldPermission } from "../lib/resolve-permission";
import { runRequiredCheck, safeValidateField } from "../lib/validate";
import { formatFieldValue } from "../lib/format-value";
import type { FieldIds } from "../hooks/use-id-factory";
import { FieldError } from "./field-error";
import { PermissionTooltip } from "./permission-tooltip";
import { FieldString } from "./field-string";
import { FieldNumber } from "./field-number";
import { FieldBoolean } from "./field-boolean";
import { FieldDate } from "./field-date";
import { FieldSelect } from "./field-select";
import { FieldTextarea } from "./field-textarea";
import { cn } from "@/lib/utils";

interface FieldRowProps {
  field: PropertiesFormField;
  values: Record<string, unknown>;
  mode: FormMode;
  error: string | undefined;
  errorVisible: boolean;
  pending: boolean;
  hostResolver?: (
    field: PropertiesFormField,
    values: Record<string, unknown>,
  ) => FieldPermission | undefined;
  ids: FieldIds;
  onFieldChange: (
    key: string,
    nextValues: Record<string, unknown>,
    error: string | undefined,
  ) => void;
  onFieldBlur: (key: string, error: string | undefined) => void;
  registerFocusTarget: (key: string, target: FocusTarget | null) => void;
}

export interface FocusTarget {
  permission: FieldPermission;
  focus: () => void;
}

interface BuiltInComponentProps extends FieldRendererProps {
  onBlur: () => void;
  required: boolean;
}

const BUILT_IN_RENDERERS: Record<
  PropertiesFormField["type"],
  ComponentType<BuiltInComponentProps>
> = {
  string: FieldString,
  number: FieldNumber,
  boolean: FieldBoolean,
  date: FieldDate,
  select: FieldSelect,
  textarea: FieldTextarea,
};

const AUTO_COMMIT_TYPES: ReadonlySet<PropertiesFormField["type"]> = new Set([
  "select",
  "boolean",
]);

class RendererErrorBoundary extends Component<
  { fieldKey: string; errorId: string; children: ReactNode },
  { hasError: boolean }
> {
  state = { hasError: false };
  static getDerivedStateFromError() {
    return { hasError: true };
  }
  componentDidCatch(error: Error, info: ErrorInfo) {
    if (process.env.NODE_ENV !== "production") {
      console.error(
        `[properties-form] renderer crashed for field "${this.props.fieldKey}":`,
        error,
        info,
      );
    }
  }
  render() {
    if (this.state.hasError) {
      return (
        <FieldError
          id={this.props.errorId}
          message="Custom renderer crashed — see console"
        />
      );
    }
    return this.props.children;
  }
}

function FieldRowImpl({
  field,
  values,
  mode,
  error,
  errorVisible,
  pending,
  hostResolver,
  ids,
  onFieldChange,
  onFieldBlur,
  registerFocusTarget,
}: FieldRowProps) {
  const permission = useMemo(
    () => resolveFieldPermission(field, values, hostResolver),
    [field, values, hostResolver],
  );

  const value = values[field.key];
  const computeError = useCallback(
    (next: unknown, nextValues: Record<string, unknown>) => {
      const requiredError = runRequiredCheck(field, next);
      if (requiredError) return requiredError;
      return safeValidateField(field, next, nextValues);
    },
    [field],
  );

  const handleChange = useCallback(
    (nextValue: unknown) => {
      const nextValues = { ...values, [field.key]: nextValue };
      const nextError = computeError(nextValue, nextValues);
      onFieldChange(field.key, nextValues, nextError);
      if (AUTO_COMMIT_TYPES.has(field.type)) {
        onFieldBlur(field.key, nextError);
      }
    },
    [values, field.key, field.type, computeError, onFieldChange, onFieldBlur],
  );

  const handleBlur = useCallback(() => {
    const blurError = computeError(values[field.key], values);
    onFieldBlur(field.key, blurError);
  }, [values, field.key, computeError, onFieldBlur]);

  const dev = process.env.NODE_ENV !== "production";
  if (field.type === "select" && (!field.options || field.options.length === 0)) {
    if (dev) {
      console.error(
        `[properties-form] select field "${field.key}" is missing \`options\`.`,
      );
    }
  }

  if (permission === "hidden") return null;

  const showError = errorVisible && !!error;
  const ariaDescribedBy =
    [
      field.description ? ids.descriptionId : undefined,
      showError ? ids.errorId : undefined,
    ]
      .filter(Boolean)
      .join(" ") || undefined;

  const rendererProps: FieldRendererProps = {
    value,
    onChange: handleChange,
    field,
    allValues: values,
    mode,
    error: showError ? error : undefined,
    disabled: permission === "read-only" || pending,
    fieldId: ids.fieldId,
    errorId: ids.errorId,
  };

  let content: ReactNode;

  if (mode === "edit" && permission === "read-only") {
    const display = formatFieldValue(field, value);
    content = (
      <PermissionTooltip
        reason={field.permissionReason ?? "This field is read-only."}
        tooltipId={ids.permissionTooltipId}
      >
        <span
          ref={(el) =>
            registerFocusTarget(field.key, el ? { permission, focus: () => el.focus() } : null)
          }
          aria-readonly="true"
          aria-describedby={ariaDescribedBy}
          className="block min-h-8 truncate rounded-md bg-muted/30 px-2 py-1 text-sm text-muted-foreground"
        >
          {display}
        </span>
      </PermissionTooltip>
    );
  } else if (field.renderer) {
    const CustomRenderer = field.renderer;
    content = (
      <RendererErrorBoundary fieldKey={field.key} errorId={ids.errorId}>
        <div
          ref={(el) =>
            registerFocusTarget(
              field.key,
              el
                ? {
                    permission,
                    focus: () => {
                      const focusable = el.querySelector<HTMLElement>(
                        "input, textarea, select, button, [tabindex]:not([tabindex=\"-1\"])",
                      );
                      (focusable ?? el).focus();
                    },
                  }
                : null,
            )
          }
        >
          <CustomRenderer {...rendererProps} />
        </div>
      </RendererErrorBoundary>
    );
  } else if (mode === "read") {
    const display = formatFieldValue(field, value);
    content = <span className="block truncate text-sm">{display}</span>;
  } else {
    const Renderer = BUILT_IN_RENDERERS[field.type];
    content = (
      <div
        ref={(el) =>
          registerFocusTarget(
            field.key,
            el
              ? {
                  permission,
                  focus: () => {
                    const focusable = el.querySelector<HTMLElement>(
                      `#${CSS.escape(ids.fieldId)}, input, textarea, button, [role="combobox"]`,
                    );
                    (focusable ?? el).focus();
                  },
                }
              : null,
          )
        }
      >
        <Renderer
          {...rendererProps}
          onBlur={handleBlur}
          required={!!field.required}
        />
      </div>
    );
  }

  return (
    <div className={cn("flex flex-col gap-1.5")}>
      <label
        htmlFor={ids.fieldId}
        className="flex items-center gap-1 text-sm font-medium text-foreground"
      >
        <span>{field.label}</span>
        {field.required ? (
          <span aria-hidden="true" className="text-destructive">
            *
          </span>
        ) : null}
      </label>
      {field.description ? (
        <p
          id={ids.descriptionId}
          className="text-xs text-muted-foreground"
        >
          {field.description}
        </p>
      ) : null}
      {content}
      {showError && error ? (
        <FieldError id={ids.errorId} message={error} />
      ) : null}
    </div>
  );
}

