import { useEffect, useRef } from "react";

const SPINNER_DELAY_MS = 200;

export function useSubmitSpinner(
  pending: boolean,
  onShow: () => void,
): void {
  const timerRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  useEffect(() => {
    if (!pending) {
      if (timerRef.current !== null) {
        clearTimeout(timerRef.current);
        timerRef.current = null;
      }
      return;
    }
    timerRef.current = setTimeout(() => {
      timerRef.current = null;
      onShow();
    }, SPINNER_DELAY_MS);
    return () => {
      if (timerRef.current !== null) {
        clearTimeout(timerRef.current);
        timerRef.current = null;
      }
    };
  }, [pending, onShow]);
}

type Flat = Record<string, unknown>;

function isPlainObject(v: unknown): v is Record<string, unknown> {
  if (v === null || typeof v !== "object") return false;
  const proto = Object.getPrototypeOf(v);
  return proto === null || proto === Object.prototype;
}

export function flatten(
  obj: Record<string, unknown>,
  prefix = "",
): Flat {
  const out: Flat = {};
  for (const [key, value] of Object.entries(obj)) {
    const next = prefix ? `${prefix}.${key}` : key;
    if (isPlainObject(value)) {
      Object.assign(out, flatten(value as Record<string, unknown>, next));
    } else {
      out[next] = value;
    }
  }
  return out;
}

export function unflatten(flat: Flat): Record<string, unknown> {
  const out: Record<string, unknown> = {};
  for (const [path, value] of Object.entries(flat)) {
    const segments = path.split(".");
    let cursor = out;
    for (let i = 0; i < segments.length - 1; i++) {
      const seg = segments[i];
      const existing = cursor[seg];
      if (!isPlainObject(existing)) {
        cursor[seg] = {};
      }
      cursor = cursor[seg] as Record<string, unknown>;
    }
    cursor[segments[segments.length - 1]] = value;
  }
  return out;
}

import type { PropertiesFormField } from "../types";

const EMPTY_DASH = "—";

export function formatFieldValue(
  field: PropertiesFormField,
  value: unknown,
): string {
  if (value === undefined || value === null) return EMPTY_DASH;
  switch (field.type) {
    case "string":
    case "textarea":
      return typeof value === "string" && value.length > 0 ? value : EMPTY_DASH;
    case "number":
      if (typeof value === "number" && Number.isFinite(value)) {
        return String(value);
      }
      if (typeof value === "string" && value.length > 0) return value;
      return EMPTY_DASH;
    case "boolean":
      return value ? "Yes" : "No";
    case "date":
      if (typeof value === "string" && value.length > 0) return value;
      if (value instanceof Date && !Number.isNaN(value.getTime())) {
        return value.toISOString().slice(0, 10);
      }
      return EMPTY_DASH;
    case "select": {
      const stringValue = typeof value === "string" ? value : String(value);
      const match = field.options?.find((o) => o.value === stringValue);
      return match?.label ?? stringValue;
    }
    default:
      return String(value);
  }
}

export const EMPTY_DISPLAY = EMPTY_DASH;

import type {
  FieldPermission,
  PropertiesFormField,
} from "../types";

export function resolveFieldPermission(
  field: PropertiesFormField,
  values: Record<string, unknown>,
  hostResolver?: (
    field: PropertiesFormField,
    values: Record<string, unknown>,
  ) => FieldPermission | undefined,
): FieldPermission {
  if (hostResolver) {
    let hostResult: FieldPermission | undefined;
    try {
      hostResult = hostResolver(field, values);
    } catch (err) {
      if (process.env.NODE_ENV !== "production") {
        console.error(
          `[properties-form] resolvePermission threw for field "${field.key}":`,
          err,
        );
      }
      hostResult = undefined;
    }
    if (hostResult !== undefined) return hostResult;
  }
  if (field.permission !== undefined) return field.permission;
  return "editable";
}

import type { PropertiesFormField } from "../types";

const VALIDATOR_THROW_MESSAGE = "Validation error — see console";

export function safeValidateField(
  field: PropertiesFormField,
  value: unknown,
  allValues: Record<string, unknown>,
): string | undefined {
  if (!field.validate) return undefined;
  try {
    return field.validate(value, allValues);
  } catch (err) {
    if (process.env.NODE_ENV !== "production") {
      console.error(
        `[properties-form] validate threw for field "${field.key}":`,
        err,
      );
    }
    return VALIDATOR_THROW_MESSAGE;
  }
}

export function runRequiredCheck(
  field: PropertiesFormField,
  value: unknown,
): string | undefined {
  if (!field.required) return undefined;
  if (value === undefined || value === null) return "Required";
  if (typeof value === "string" && value.trim().length === 0) return "Required";
  return undefined;
}

export function validateAllFields(
  schema: ReadonlyArray<PropertiesFormField>,
  values: Record<string, unknown>,
): Record<string, string> {
  const errors: Record<string, string> = {};
  for (const field of schema) {
    if (field.permission === "hidden") continue;
    const value = values[field.key];
    const requiredError = runRequiredCheck(field, value);
    if (requiredError) {
      errors[field.key] = requiredError;
      continue;
    }
    const userError = safeValidateField(field, value, values);
    if (userError) errors[field.key] = userError;
  }
  return errors;
}

export function safeRunFormValidate<T extends Record<string, unknown>>(
  hostValidate: ((values: T) => Record<string, string> | undefined) | undefined,
  values: T,
): { errors: Record<string, string>; formError: string | undefined } {
  if (!hostValidate) return { errors: {}, formError: undefined };
  try {
    const result = hostValidate(values);
    return { errors: result ?? {}, formError: undefined };
  } catch (err) {
    if (process.env.NODE_ENV !== "production") {
      console.error("[properties-form] form-level validate threw:", err);
    }
    return { errors: {}, formError: VALIDATOR_THROW_MESSAGE };
  }
}
